import Vue from "vue";
import App from "./App.vue";
import Home from "./components/Home.vue";
import Projects from "./components/Projects.vue";
import Poker from "./components/Poker.vue";
import DefaultPoker from "./components/poker/DefaultPoker.vue";
import Numbers from "./components/poker/Numbers.vue";
import Pcalculator from "./components/poker/Pcalculator.vue";
import Fun from "./components/Fun.vue";
import DefaultFun from "./components/fun/DefaultFun.vue";
import Exercises from "./components/fun/Exercises.vue";
import Pondercises from "./components/fun/Pondercises.vue";
import Contact from "./components/Contact.vue";
import VueRouter from "vue-router";
import VueResource from "vue-resource";
Vue.use(VueResource);
Vue.use(VueRouter);

const routes = [
  {path: '/', component: Home},
  {path: '/projects', component: Projects},
  {
    path: '/poker', component: Poker,
    children: [
      {path: '', component: DefaultPoker},
      {path: 'numbers', component: Numbers},
      {path: 'pcalculator', component: Pcalculator}
    ]
  },
  {
    path: '/fun', component: Fun,
    children: [
      {path: '', component: DefaultFun},
      {path: 'exercises', component: Exercises},
      {path: 'pondercises', component: Pondercises}
    ]
  },
  {path: '/contact', component: Contact},
  {path: '*', redirect: '/'}
];

const router = new VueRouter({routes});

/*
 https://github.com/vuejs/vue-router/blob/dev/examples/auth-flow/app.js
 */
const app = new Vue({
  el: '#app',
  router,
  render: h => h(App)
});



